def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about airports (or related entities) into a single
    fluent, complex sentence. Unknown predicates fall back to a generic phrasing.
    """
    if not triples:
        return ""

    def _clean(val: str) -> str:
        """Remove surrounding quotes if present."""
        return val.strip('"').strip("'")

    # Group triples by subject for better sentence construction
    airport_triples = [t for t in triples if "Airport" in t.subject or "Airport" in t.object]
    location_triples = [t for t in triples if t.predicate in ["country", "capital", "language", "officialLanguage", "leader", "leaderTitle", "leaderParty", "largestCity", "owner", "isPartOf", "countySeat", "ceremonialCounty", "regionServed", "jurisdiction", "currency", "demonym", "areaCode", "postalCode", "foundedBy", "foundingYear", "nativeName", "headquarter", "class", "division", "order", "mayor", "administrativeArrondissement", "demonym", "transportAircraft", "aircraftHelicopter", "aircraftFighter", "attackAircraft", "battle", "hubAirport", "regionServed", "chief"]]

    # Build main clause for the airport
    def _main_clause(s: str, p: str, o: str) -> str:
        """Build the primary clause for an airport."""
        if p == "cityServed":
            return f"{s} serves the city of {o}"
        if p == "location":
            return f"{s} is located in {o}"
        if p == "country":
            return f"{s} is in {o}"
        if p == "elevationAboveTheSeaLevel":
            return f"{s} lies at an elevation of {o} metres above sea level"
        if p == "elevationAboveTheSeaLevelInFeet":
            return f"{s} lies at an elevation of {o} feet above sea level"
        if p == "elevationAboveTheSeaLevelInMetres":
            return f"{s} is at an elevation of {o} metres above sea level"
        if p == "operatingOrganisation":
            return f"{s} is operated by {o}"
        if p == "owner":
            return f"{s} is owned by {o}"
        if p == "runwaySurfaceType":
            return f"{s} has a runway surface of {o}"
        if p == "runwayLength":
            return f"{s} has a runway length of {o}"
        if p == "runwayName":
            return f"{s}'s runway is named {o}"
        if p == "iataLocationIdentifier":
            return f"{s} has IATA code {o}"
        if p == "icaoLocationIdentifier":
            return f"{s} has ICAO code {o}"
        if p == "locationIdentifier":
            return f"{s} has location identifier {o}"
        if p == "nativeName":
            return f"{s} is known as {o}"
        if p == "isPartOf":
            return f"{s} is part of {o}"
        if p == "largestCity":
            return f"{s}'s largest city is {o}"
        if p == "capital":
            return f"{s}'s capital is {o}"
        if p == "leader":
            return f"{s} is led by {o}"
        if p == "leaderParty":
            return f"{s}'s leader belongs to the {o} party"
        if p == "leaderTitle":
            return f"{s}'s leader title is {o}"
        if p == "language":
            return f"The language of {s} is {o}"
        if p == "officialLanguage":
            return f"The official language of {s} is {o}"
        if p == "currency":
            return f"The currency of {s} is {o}"
        if p == "demonym":
            return f"The demonym of {s} is {o}"
        if p == "mayor":
            return f"The mayor of {s} is {o}"
        if p == "administrativeArrondissement":
            return f"{s} is in the {o} administrative arrondissement"
        if p == "ceremonialCounty":
            return f"{s} is in the ceremonial county of {o}"
        if p == "countySeat":
            return f"{s}'s county seat is {o}"
        if p == "areaCode":
            return f"{s} has area code {o}"
        if p == "postalCode":
            return f"{s} has postal code {o}"
        if p == "foundedBy":
            return f"{s} was founded by {o}"
        if p == "foundingYear":
            return f"{s} was founded in {o}"
        if p == "headquarter":
            return f"{s} has its headquarters at {o}"
        if p == "regionServed":
            return f"{s} serves the region of {o}"
        if p == "jurisdiction":
            return f"{s} has jurisdiction over {o}"
        if p == "hubAirport":
            return f"{s} is a hub airport for {o}"
        if p == "transportAircraft":
            return f"{s} operates {o}"
        if p == "aircraftHelicopter":
            return f"{s} operates {o}"
        if p == "aircraftFighter":
            return f"{s} operates {o}"
        if p == "attackAircraft":
            return f"{s} operates {o}"
        if p == "battle":
            return f"{s} participated in {o}"
        if p == "chief":
            return f"{s} is led by {o}"
        if p == "class":
            return f"{s} is classified as {o}"
        if p == "division":
            return f"{s} is part of the {o} division"
        if p == "order":
            return f"{s} is in the {o} order"
        # Runway length variants
        if p.endswith("RunwayLengthFeet"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} feet long"
        if p.endswith("RunwayLengthMetre"):
            idx = p.split("Runway")[0]
            return f"{s}'s {idx.lower()} runway is {o} metres long"
        # Fallback for any other predicate
        return f"{s} has {p} {o}"

    # Build clauses
    clauses: list[str] = [_main_clause(t.subject, t.predicate, _clean(t.object)) for t in triples]

    # Combine clauses into a single complex sentence
    if len(clauses) == 1:
        sentence = clauses[0] + "."
    else:
        sentence = ", ".join(clauses[:-1]) + ", and " + clauses[-1] + "."

    # Capitalise first character
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END

